&lt;/td&gt;
&lt;td&gt;
&lt;p&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Authentication, login, sessions, multi-account, and access control.&lt;/span&gt;&lt;/p&gt;
&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;
&lt;p&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Account Protection&lt;/span&gt;&lt;/p&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;p&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Customer-facing security at the account layer — OTP, device, and account-level fraud protections.&lt;/span&gt;&lt;/p&gt;
&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;
&lt;p&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Compliance &amp;amp; Fraud Detection&lt;/span&gt;&lt;/p&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;p&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Regulatory reporting, fraud detection, and compliance tooling across all four markets.&lt;/span&gt;&lt;/p&gt;
&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;
&lt;p&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Back-Office Systems&lt;/span&gt;&lt;/p&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;p&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Internal operations and back-office tooling used by ops and compliance teams.&lt;/span&gt;&lt;/p&gt;
&lt;/td&gt;
